import { PublicCard } from '../../../types';

export const mcatCards: PublicCard[] = [
  // --- Biology & Biochemistry ---
  { id: 'dc-mcat-0001', deck_id: 'deck-mcat', sort_order: 1, front: "Michaelis-Menten Equation", back: "v = Vmax[S] / (Km + [S]). Describes enzyme kinetics: Km is the substrate concentration at half-maximal velocity; lower Km indicates higher enzyme affinity for substrate." },
  { id: 'dc-mcat-0002', deck_id: 'deck-mcat', sort_order: 2, front: "Vmax and Enzyme Concentration", back: "Vmax is directly proportional to the total enzyme concentration [E]T. Adding more enzyme increases Vmax but does not change Km. Competitive inhibitors increase apparent Km; non-competitive inhibitors decrease Vmax." },
  { id: 'dc-mcat-0003', deck_id: 'deck-mcat', sort_order: 3, front: "Competitive Inhibition (Kinetics)", back: "Increases apparent Km (reduces apparent affinity); Vmax is unchanged because inhibitor can be outcompeted by excess substrate. On a Lineweaver-Burk plot, the x-intercept shifts but y-intercept stays the same." },
  { id: 'dc-mcat-0004', deck_id: 'deck-mcat', sort_order: 4, front: "Non-Competitive Inhibition (Kinetics)", back: "Inhibitor binds allosteric site regardless of substrate; decreases Vmax but Km is unchanged. Cannot be overcome by adding more substrate. On a Lineweaver-Burk plot, y-intercept increases but x-intercept stays the same." },
  { id: 'dc-mcat-0005', deck_id: 'deck-mcat', sort_order: 5, front: "Feedback Inhibition", back: "A regulatory mechanism where the end product of a metabolic pathway inhibits an enzyme earlier in the pathway, usually the first committed step. Common in amino acid biosynthesis; prevents overproduction of a product." },
  { id: 'dc-mcat-0006', deck_id: 'deck-mcat', sort_order: 6, front: "Cell Signaling: G-Protein Coupled Receptor (GPCR)", back: "A ligand binds the receptor, activating a G-protein (GDP → GTP exchange). The G-protein activates/inhibits effectors (adenylyl cyclase, phospholipase C). Key second messengers: cAMP, IP₃, DAG, Ca²⁺." },
  { id: 'dc-mcat-0007', deck_id: 'deck-mcat', sort_order: 7, front: "Receptor Tyrosine Kinase (RTK)", back: "A transmembrane receptor that dimerizes and autophosphorylates tyrosine residues upon ligand binding. Activates downstream cascades (RAS-MAPK, PI3K-Akt). Important in growth factor signaling (EGF, insulin receptor)." },
  { id: 'dc-mcat-0008', deck_id: 'deck-mcat', sort_order: 8, front: "Protein Structure: Primary to Quaternary", back: "1°: amino acid sequence. 2°: α-helix and β-sheet from backbone H-bonds. 3°: 3D folding from R-group interactions (hydrophobic, disulfide, ionic, H-bonds). 4°: multiple subunit assembly (e.g., hemoglobin)." },
  { id: 'dc-mcat-0009', deck_id: 'deck-mcat', sort_order: 9, front: "Membrane Transport: Simple Diffusion", back: "Passive movement of small, nonpolar molecules (O₂, CO₂, ethanol) directly through the lipid bilayer down their concentration gradient. No protein, no energy required. Rate is proportional to concentration gradient." },
  { id: 'dc-mcat-0010', deck_id: 'deck-mcat', sort_order: 10, front: "Membrane Transport: Facilitated Diffusion", back: "Passive transport of larger or polar molecules via protein channels or carriers, down their concentration gradient. No ATP required. Examples: glucose uptake by GLUT transporters, ion movement through channels." },
  { id: 'dc-mcat-0011', deck_id: 'deck-mcat', sort_order: 11, front: "Glycolysis (Steps Overview)", back: "10-step pathway in the cytoplasm. Investment phase: 2 ATP consumed. Payoff phase: 4 ATP produced. Net: 2 ATP, 2 NADH, 2 pyruvate per glucose. Key regulatory enzyme: PFK-1 (inhibited by ATP, citrate; activated by AMP, ADP)." },
  { id: 'dc-mcat-0012', deck_id: 'deck-mcat', sort_order: 12, front: "Pyruvate Decarboxylation", back: "Pyruvate (3C) is converted to acetyl-CoA (2C) + CO₂ + NADH in the mitochondrial matrix by pyruvate dehydrogenase complex. Irreversible step linking glycolysis to the Krebs cycle. Inhibited by its own products (NADH, acetyl-CoA)." },
  { id: 'dc-mcat-0013', deck_id: 'deck-mcat', sort_order: 13, front: "TCA Cycle (Krebs Cycle) Yield", back: "Per acetyl-CoA turn: 3 NADH, 1 FADH₂, 1 GTP (ATP), 2 CO₂. Per glucose (two turns): 6 NADH, 2 FADH₂, 2 GTP. Occurs in the mitochondrial matrix; all intermediates regenerate oxaloacetate." },
  { id: 'dc-mcat-0014', deck_id: 'deck-mcat', sort_order: 14, front: "Electron Transport Chain (ETC)", back: "Located in the inner mitochondrial membrane. NADH enters at Complex I (4H⁺ pumped), FADH₂ at Complex II (0H⁺). Complexes I, III, IV pump H⁺ into the intermembrane space. O₂ is the final electron acceptor (→ H₂O)." },
  { id: 'dc-mcat-0015', deck_id: 'deck-mcat', sort_order: 15, front: "ATP Synthase (Complex V)", back: "Uses the proton gradient (chemiosmosis) established by the ETC to synthesize ATP as protons flow back into the matrix. Approximately 2.5 ATP per NADH and 1.5 ATP per FADH₂ by current estimates." },
  { id: 'dc-mcat-0016', deck_id: 'deck-mcat', sort_order: 16, front: "Fatty Acid Beta-Oxidation", back: "Each cycle of β-oxidation cleaves a 2-carbon unit from an acyl-CoA, yielding acetyl-CoA, 1 NADH, and 1 FADH₂. Occurs in the mitochondrial matrix. Long-chain fatty acids require carnitine shuttle to enter mitochondria." },
  { id: 'dc-mcat-0017', deck_id: 'deck-mcat', sort_order: 17, front: "Ketogenesis", back: "In fasting/starvation, excess acetyl-CoA (from fat breakdown) is converted to ketone bodies (acetoacetate, β-hydroxybutyrate, acetone) in the liver. Exported as fuel for brain and muscle when glucose is scarce." },
  { id: 'dc-mcat-0018', deck_id: 'deck-mcat', sort_order: 18, front: "Gluconeogenesis", back: "Synthesis of glucose from non-carbohydrate precursors (lactate, glycerol, alanine, oxaloacetate) in the liver and kidney cortex. Occurs during fasting. Essentially the reverse of glycolysis, with 3 unique bypass enzymes." },
  { id: 'dc-mcat-0019', deck_id: 'deck-mcat', sort_order: 19, front: "Glycogen Synthesis and Breakdown", back: "Glycogenesis: glucose-6-P → glycogen (liver and muscle); insulin stimulates, glucagon inhibits. Glycogenolysis: glycogen → glucose-1-P (glucagon and epinephrine stimulate). Liver glycogen maintains blood glucose; muscle for local use." },
  { id: 'dc-mcat-0020', deck_id: 'deck-mcat', sort_order: 20, front: "Amino Acid Catabolism", back: "Amino groups are removed by transamination (to α-ketoglutarate, forming glutamate) or oxidative deamination. NH₃ is toxic; converted to urea (urea cycle) in the liver. Carbon skeletons enter TCA as various intermediates." },
  { id: 'dc-mcat-0021', deck_id: 'deck-mcat', sort_order: 21, front: "DNA Replication: Key Enzymes", back: "Helicase: unwinds double helix. Primase: synthesizes RNA primers. DNA polymerase III: extends primers 5'→3'. DNA polymerase I: removes RNA primers, fills gaps. Ligase: joins Okazaki fragments on lagging strand." },
  { id: 'dc-mcat-0022', deck_id: 'deck-mcat', sort_order: 22, front: "Transcription: Key Features in Eukaryotes", back: "RNA polymerase II transcribes mRNA; requires general transcription factors and promoter (TATA box ~25 bp upstream). Pre-mRNA processing: 5' 7-methylguanosine cap, 3' poly-A tail, splicing of introns by spliceosome." },
  { id: 'dc-mcat-0023', deck_id: 'deck-mcat', sort_order: 23, front: "Translation: Initiation, Elongation, Termination", back: "Initiation: small ribosomal subunit binds mRNA at AUG (start codon), initiator Met-tRNA, large subunit joins. Elongation: A-site (aminoacyl), P-site (peptidyl), E-site (exit); peptidyl transferase forms peptide bond. Termination: stop codon recognized by release factor." },
  { id: 'dc-mcat-0024', deck_id: 'deck-mcat', sort_order: 24, front: "DNA Repair Mechanisms", back: "Nucleotide excision repair (NER): removes bulky lesions (UV-induced pyrimidine dimers). Base excision repair (BER): removes damaged/modified bases. Mismatch repair (MMR): corrects replication errors. NHEJ and HR repair double-strand breaks." },
  { id: 'dc-mcat-0025', deck_id: 'deck-mcat', sort_order: 25, front: "Cell Cycle Checkpoints", back: "G1/S checkpoint (restriction point): checks DNA integrity and cell size; regulated by CDK4/6-cyclin D and p53/p21. G2/M checkpoint: checks DNA replication completion. M checkpoint (spindle checkpoint): ensures kinetochore-microtubule attachment." },
  { id: 'dc-mcat-0026', deck_id: 'deck-mcat', sort_order: 26, front: "Tumor Suppressors vs. Proto-Oncogenes", back: "Proto-oncogenes promote cell division; mutations → oncogenes (gain-of-function; dominant). Tumor suppressors inhibit division; mutations → loss-of-function (recessive; two-hit hypothesis). Key examples: RAS (oncogene), p53, Rb (tumor suppressors)." },
  { id: 'dc-mcat-0027', deck_id: 'deck-mcat', sort_order: 27, front: "Meiosis I vs. Meiosis II", back: "Meiosis I (reductive): homologous chromosomes separate; crossing over occurs in prophase I; results in two haploid cells (each with sister chromatids). Meiosis II (equational): sister chromatids separate; similar to mitosis; results in 4 haploid cells." },
  { id: 'dc-mcat-0028', deck_id: 'deck-mcat', sort_order: 28, front: "Linked Genes and Recombination Frequency", back: "Genes on the same chromosome are linked and tend to be inherited together. Recombination frequency = (recombinant offspring / total offspring) × 100%. 1% recombination ≈ 1 centimorgan (cM) of genetic distance." },
  { id: 'dc-mcat-0029', deck_id: 'deck-mcat', sort_order: 29, front: "Eukaryotic Gene Expression Regulation", back: "Transcriptional level: enhancers, silencers, transcription factors. Post-transcriptional: alternative splicing, RNA stability. Translational: ribosome availability, initiation factors. Post-translational: phosphorylation, ubiquitination, glycosylation." },
  { id: 'dc-mcat-0030', deck_id: 'deck-mcat', sort_order: 30, front: "Virus Replication Cycle", back: "Attachment → penetration → uncoating → replication/transcription → assembly → release. DNA viruses replicate in nucleus; RNA viruses (mostly) in cytoplasm. Retroviruses use reverse transcriptase to make DNA from RNA." },
  { id: 'dc-mcat-0031', deck_id: 'deck-mcat', sort_order: 31, front: "Lac Operon (Inducible)", back: "Default state: repressor binds operator, blocking transcription. When lactose is present → allolactose binds repressor → repressor dissociates → genes transcribed. Also requires low glucose (catabolite repression via cAMP-CAP)." },
  { id: 'dc-mcat-0032', deck_id: 'deck-mcat', sort_order: 32, front: "Trp Operon (Repressible)", back: "When tryptophan is plentiful, it acts as a corepressor, binding the aporepressor to form an active repressor that blocks the operator. Also regulated by attenuation (ribosome stalling early in translation)." },
  { id: 'dc-mcat-0033', deck_id: 'deck-mcat', sort_order: 33, front: "Oxidative Phosphorylation", back: "ATP synthesis driven by the proton gradient established by the electron transport chain in the inner mitochondrial membrane. Produces ~34 ATP per glucose. Uncouplers (e.g., DNP) dissipate the gradient as heat (no ATP)." },
  { id: 'dc-mcat-0034', deck_id: 'deck-mcat', sort_order: 34, front: "Glycolysis Net Products", back: "2 ATP, 2 NADH, and 2 pyruvate per glucose molecule. Occurs in the cytoplasm; does not require oxygen (anaerobic). Under anaerobic conditions, NADH is reoxidized to NAD⁺ by fermentation to allow glycolysis to continue." },
  { id: 'dc-mcat-0035', deck_id: 'deck-mcat', sort_order: 35, front: "Pentose Phosphate Pathway", back: "An alternative glucose metabolism pathway in the cytoplasm with two phases: oxidative (produces NADPH and ribose-5-P) and non-oxidative (interconverts sugar phosphates). NADPH is essential for fatty acid synthesis and antioxidant defense (glutathione reduction)." },
  // --- General Chemistry ---
  { id: 'dc-mcat-0036', deck_id: 'deck-mcat', sort_order: 36, front: "Henderson-Hasselbalch Equation", back: "pH = pKa + log([A⁻]/[HA]). Used to calculate pH of buffer solutions; at pH = pKa, concentrations of acid and conjugate base are equal. Critical for understanding blood buffers and titration curves." },
  { id: 'dc-mcat-0037', deck_id: 'deck-mcat', sort_order: 37, front: "Buffer Systems in the Body", back: "Bicarbonate buffer: H₂CO₃ ⇌ H⁺ + HCO₃⁻ (pKa 6.1; most important blood buffer; regulated by kidneys and lungs). Phosphate buffer: H₂PO₄⁻ ⇌ H⁺ + HPO₄²⁻ (pKa 6.8; important intracellularly and in urine)." },
  { id: 'dc-mcat-0038', deck_id: 'deck-mcat', sort_order: 38, front: "Strong Acids and Bases", back: "Strong acids fully dissociate: HCl, HBr, HI, HNO₃, H₂SO₄ (1st dissociation), HClO₄. Strong bases: NaOH, KOH, Ca(OH)₂, Ba(OH)₂. Weak acids/bases partially dissociate; have Ka or Kb < 1." },
  { id: 'dc-mcat-0039', deck_id: 'deck-mcat', sort_order: 39, front: "Acid-Base Titration Curve", back: "At half-equivalence point: pH = pKa (half acid, half conjugate base). At equivalence point: stoichiometric neutralization. Strong acid + strong base: equivalence at pH 7. Weak acid + strong base: equivalence pH > 7 (hydrolysis of conjugate base)." },
  { id: 'dc-mcat-0040', deck_id: 'deck-mcat', sort_order: 40, front: "Electrochemistry: Standard Cell Potential", back: "E°cell = E°cathode - E°anode. Positive E°cell = spontaneous. ΔG° = -nFE°. n = moles of electrons transferred; F = 96,485 C/mol. At equilibrium, E = 0 and Q = K." },
  { id: 'dc-mcat-0041', deck_id: 'deck-mcat', sort_order: 41, front: "Nernst Equation (MCAT)", back: "E = E° - (0.0592/n)log(Q) at 25°C. Adjusts cell potential for non-standard concentrations. Q < 1 increases E (reaction driven forward); Q > 1 decreases E." },
  { id: 'dc-mcat-0042', deck_id: 'deck-mcat', sort_order: 42, front: "Colligative Properties", back: "Depend on the number of solute particles, not identity. Boiling point elevation: ΔTb = iKbm. Freezing point depression: ΔTf = iKfm. Osmotic pressure: π = iMRT. i = van 't Hoff factor (number of particles per formula unit)." },
  { id: 'dc-mcat-0043', deck_id: 'deck-mcat', sort_order: 43, front: "Phase Changes and Heating Curve", back: "During a phase change, temperature remains constant while heat (= mL) is absorbed or released. The slope of the heating curve reflects specific heat capacity (q = mcΔT) of each phase. Greater slope = lower specific heat." },
  { id: 'dc-mcat-0044', deck_id: 'deck-mcat', sort_order: 44, front: "Ideal Gas Law and Deviations", back: "PV = nRT. Real gases deviate at high pressure (volume effect) and low temperature (attractive forces). Van der Waals equation: (P + a/V²)(V - b) = nRT. Gas with high a = strong intermolecular forces." },
  { id: 'dc-mcat-0045', deck_id: 'deck-mcat', sort_order: 45, front: "Gibbs Free Energy and Spontaneity", back: "ΔG = ΔH - TΔS. Spontaneous when ΔG < 0. ΔG° = -RT ln K. If ΔG < 0: spontaneous; ΔG = 0: equilibrium; ΔG > 0: non-spontaneous. Exothermic (ΔH < 0) + entropy increase (ΔS > 0) = always spontaneous." },
  { id: 'dc-mcat-0046', deck_id: 'deck-mcat', sort_order: 46, front: "Radioactive Decay and Half-Life", back: "N = N₀(½)^(t/t½). After n half-lives, (½)ⁿ of the original remains. First-order process; ln 2 / λ = t½. MCAT relevant isotopes: ¹⁴C (dating), ¹³¹I (thyroid), ⁹⁹ᵐTc (imaging), ³H (tracers)." },
  { id: 'dc-mcat-0047', deck_id: 'deck-mcat', sort_order: 47, front: "Le Chatelier's Principle (MCAT Applications)", back: "Increasing reactant concentration or decreasing product concentration shifts equilibrium right. Increasing pressure favors the side with fewer moles of gas. Increasing temperature favors the endothermic direction (shifts K)." },
  { id: 'dc-mcat-0048', deck_id: 'deck-mcat', sort_order: 48, front: "Rate-Determining Step", back: "The slowest elementary step in a reaction mechanism, determining the overall reaction rate. The rate law for the overall reaction reflects only the reactants in the rate-determining step, not the overall balanced equation." },
  // --- Organic Chemistry ---
  { id: 'dc-mcat-0049', deck_id: 'deck-mcat', sort_order: 49, front: "SN2 Reaction (MCAT)", back: "Bimolecular; concerted mechanism; backside attack → inversion of configuration (Walden inversion). Rate = k[nucleophile][substrate]. Best with primary substrates, strong nucleophiles, polar aprotic solvents (DMSO, acetone)." },
  { id: 'dc-mcat-0050', deck_id: 'deck-mcat', sort_order: 50, front: "SN1 Reaction (MCAT)", back: "Unimolecular; two-step via carbocation intermediate. Rate = k[substrate]. Best with tertiary substrates, weak nucleophiles, polar protic solvents (water, alcohol). Produces racemic mixture (both enantiomers)." },
  { id: 'dc-mcat-0051', deck_id: 'deck-mcat', sort_order: 51, front: "E2 Elimination", back: "Bimolecular; concerted; anti-periplanar geometry required (H and LG at 180°). Rate = k[base][substrate]. Strong, bulky base (KOtBu). Major product follows Zaitsev's rule (more substituted alkene) unless bulky base gives Hofmann product." },
  { id: 'dc-mcat-0052', deck_id: 'deck-mcat', sort_order: 52, front: "E1 Elimination", back: "Unimolecular; proceeds via carbocation intermediate (like SN1). Rate = k[substrate]. Follows Zaitsev's rule. Competes with SN1. Tertiary substrates, high temperature, and weak nucleophile/base favor E1." },
  { id: 'dc-mcat-0053', deck_id: 'deck-mcat', sort_order: 53, front: "Stereochemistry: R/S Configuration", back: "Assign priorities 1–4 by CIP rules (atomic number). If priority 1→2→3 is clockwise = R; counterclockwise = S. If the lowest priority (4) is facing you, reverse the designation. Chiral center: 4 different groups on carbon." },
  { id: 'dc-mcat-0054', deck_id: 'deck-mcat', sort_order: 54, front: "Stereochemistry: Enantiomers vs. Diastereomers", back: "Enantiomers: non-superimposable mirror images; opposite configuration at all stereocenters. Diastereomers: stereoisomers that are not mirror images; different configuration at one or more (not all) stereocenters. Meso compounds are achiral despite stereocenters." },
  { id: 'dc-mcat-0055', deck_id: 'deck-mcat', sort_order: 55, front: "Carbohydrate Anomers (α vs. β)", back: "When monosaccharides cyclize, the anomeric carbon (C1 of aldoses) can adopt α (OH below the ring plane in Haworth) or β (OH above) configuration. β-glucose is more stable and is the monomer of cellulose; α-glucose forms starch and glycogen." },
  { id: 'dc-mcat-0056', deck_id: 'deck-mcat', sort_order: 56, front: "Lipids: Phospholipid Structure", back: "A glycerophospholipid has: glycerol backbone + two fatty acid tails (ester bonds) + phosphate group + polar head group. Amphipathic: hydrophilic head (phosphate + head group) and hydrophobic tails. Forms bilayers spontaneously in water." },
  { id: 'dc-mcat-0057', deck_id: 'deck-mcat', sort_order: 57, front: "Amino Acid Classification", back: "Non-polar aliphatic: Gly, Ala, Val, Leu, Ile, Pro, Met. Aromatic: Phe, Tyr, Trp. Polar uncharged: Ser, Thr, Cys, Asn, Gln. Positively charged (+): Arg, Lys, His. Negatively charged (−): Asp, Glu. 20 standard amino acids." },
  { id: 'dc-mcat-0058', deck_id: 'deck-mcat', sort_order: 58, front: "Amino Acid: Isoelectric Point (pI)", back: "The pH at which an amino acid (or protein) has no net charge (zwitterionic). pI = (pKa1 + pKa2) / 2 for simple amino acids. For basic AA (Lys): pI uses pKa of the two most basic groups. At pH > pI, protein has net negative charge." },
  { id: 'dc-mcat-0059', deck_id: 'deck-mcat', sort_order: 59, front: "Nucleotides: Structure and Function", back: "Composed of a nitrogenous base, pentose sugar (ribose or deoxyribose), and 1–3 phosphate groups. Purines: adenine (A), guanine (G); 2 rings. Pyrimidines: cytosine (C), thymine (T/DNA only), uracil (U/RNA only); 1 ring." },
  { id: 'dc-mcat-0060', deck_id: 'deck-mcat', sort_order: 60, front: "DNA vs. RNA: Structural Differences", back: "DNA: deoxyribose (no 2'-OH), bases A/T/G/C, double-stranded, stable. RNA: ribose (2'-OH makes it less stable), bases A/U/G/C, typically single-stranded. The 2'-OH makes RNA susceptible to hydrolysis under alkaline conditions." },
  { id: 'dc-mcat-0061', deck_id: 'deck-mcat', sort_order: 61, front: "Aldol Condensation", back: "An enolizable carbonyl compound acts as a nucleophile (as its enolate) attacking another carbonyl compound, forming a β-hydroxy carbonyl (aldol addition), which can dehydrate to form an α,β-unsaturated carbonyl (aldol condensation)." },
  { id: 'dc-mcat-0062', deck_id: 'deck-mcat', sort_order: 62, front: "Nucleophilic Acyl Substitution", back: "Carboxylic acid derivatives (acyl chlorides > anhydrides > esters > amides, in decreasing reactivity) undergo substitution at the carbonyl carbon: nucleophile adds → tetrahedral intermediate → leaving group departs." },
  { id: 'dc-mcat-0063', deck_id: 'deck-mcat', sort_order: 63, front: "Aromatic Electrophilic Substitution (EAS)", back: "Benzene rings react with electrophiles (E⁺), not in addition (which would destroy aromaticity), but in substitution. Activating groups (OH, NH₂, alkyl) direct ortho/para; deactivating groups (NO₂, CN, COOH) direct meta." },
  { id: 'dc-mcat-0064', deck_id: 'deck-mcat', sort_order: 64, front: "Oxidation and Reduction of Organic Compounds", back: "Oxidation: addition of O or loss of H (increases carbon oxidation state). Reduction: loss of O or addition of H. Alcohol → aldehyde/ketone → carboxylic acid (progressive oxidation). Common oxidizers: KMnO₄, CrO₃, PCC (mild, stops at aldehyde)." },
  { id: 'dc-mcat-0065', deck_id: 'deck-mcat', sort_order: 65, front: "IR Spectroscopy Key Absorptions", back: "O–H stretch: broad 2500–3300 cm⁻¹ (carboxylic acid) or 3200–3550 cm⁻¹ (alcohol). N–H stretch: 3300–3500 cm⁻¹. C=O stretch (carbonyl): 1630–1850 cm⁻¹. C=C stretch: 1620–1680 cm⁻¹. C–H stretch: ~3000 cm⁻¹." },
  // --- Physics ---
  { id: 'dc-mcat-0066', deck_id: 'deck-mcat', sort_order: 66, front: "Ohm's Law and Circuits (MCAT)", back: "V = IR. Series: same current, voltages add (R_total = ΣR). Parallel: same voltage, currents add (1/R_total = Σ1/R). Power: P = IV = I²R = V²/R. Capacitors: opposite of resistors in series/parallel." },
  { id: 'dc-mcat-0067', deck_id: 'deck-mcat', sort_order: 67, front: "Fluids: Pressure and Buoyancy", back: "P = ρgh (hydrostatic pressure). Buoyant force F_b = ρ_fluid·V_submerged·g (Archimedes). An object floats if ρ_object < ρ_fluid. Clinical relevance: lung buoyancy, IV fluid pressure, cerebrospinal fluid." },
  { id: 'dc-mcat-0068', deck_id: 'deck-mcat', sort_order: 68, front: "Bernoulli's Principle and Poiseuille's Law", back: "Bernoulli: P + ½ρv² + ρgh = constant (flow speed and pressure inversely related). Poiseuille: Q = πr⁴ΔP/(8ηL). Flow is proportional to r⁴ — doubling radius increases flow 16-fold. Relevant to vascular resistance." },
  { id: 'dc-mcat-0069', deck_id: 'deck-mcat', sort_order: 69, front: "Optics: Lenses and Mirrors", back: "Thin lens equation: 1/f = 1/do + 1/di. Convex lens (converging): f > 0. Concave lens (diverging): f < 0. Magnification: m = -di/do. Real images: di > 0 (opposite side of lens); virtual images: di < 0 (same side as object)." },
  { id: 'dc-mcat-0070', deck_id: 'deck-mcat', sort_order: 70, front: "Sound: Intensity and Decibels", back: "β = 10 log(I/I₀), I₀ = 10⁻¹² W/m². Every 10 dB increase = 10× intensity. Frequency of sound perceived as pitch. Speed of sound ≈ 343 m/s in air; much faster in liquids and solids. Ultrasound uses frequencies >20,000 Hz." },
  { id: 'dc-mcat-0071', deck_id: 'deck-mcat', sort_order: 71, front: "Electromagnetic Spectrum (MCAT)", back: "Radio → microwave → infrared → visible (ROYGBIV) → ultraviolet → X-ray → gamma. Higher frequency = higher energy = shorter wavelength. Gamma rays have highest energy (nuclear decay); UV causes DNA damage (thymine dimers)." },
  { id: 'dc-mcat-0072', deck_id: 'deck-mcat', sort_order: 72, front: "Photoelectric Effect (MCAT)", back: "Electrons ejected from a metal when light of sufficient frequency (not intensity) strikes it. E_k = hf - φ. If hf < φ (work function), no electrons are ejected regardless of intensity. Demonstrates photon nature of light." },
  { id: 'dc-mcat-0073', deck_id: 'deck-mcat', sort_order: 73, front: "Nuclear Reactions: Alpha, Beta, Gamma", back: "Alpha (α) decay: Z decreases by 2, A decreases by 4. Beta-minus (β⁻) decay: n → p, Z increases by 1, A unchanged; emits electron + antineutrino. Gamma (γ) decay: no change in Z or A; emits high-energy photon from excited nucleus." },
  { id: 'dc-mcat-0074', deck_id: 'deck-mcat', sort_order: 74, front: "E = mc² and Mass Defect", back: "Nuclear binding energy = Δm × c². Mass defect is the difference between the mass of a nucleus and the sum of masses of its constituent nucleons. This lost mass is converted to binding energy. Iron-56 has the greatest binding energy per nucleon." },
  { id: 'dc-mcat-0075', deck_id: 'deck-mcat', sort_order: 75, front: "Work, Energy, and Power (MCAT)", back: "W = Fd·cosθ. KE = ½mv². PE = mgh. Conservation of energy: KE + PE = constant (no friction). Power P = W/t = Fv. The work-energy theorem: net work = ΔKE. On the MCAT, check for conservative vs. non-conservative forces." },
  { id: 'dc-mcat-0076', deck_id: 'deck-mcat', sort_order: 76, front: "Projectile Motion (MCAT)", back: "Horizontal: constant velocity (v_x = v₀cosθ, x = v_xt). Vertical: constant acceleration g downward (y = v₀sinθ·t - ½gt²). Range is maximized at 45°. The two components are completely independent." },
  { id: 'dc-mcat-0077', deck_id: 'deck-mcat', sort_order: 77, front: "Springs and Simple Harmonic Motion", back: "F = -kx (Hooke's Law). T = 2π√(m/k) for spring; T = 2π√(L/g) for pendulum. Maximum KE at equilibrium (x=0); maximum PE at maximum displacement. Total mechanical energy is conserved: E = ½kA²." },
  { id: 'dc-mcat-0078', deck_id: 'deck-mcat', sort_order: 78, front: "Torque and Rotational Equilibrium", back: "τ = rFsinθ. For rotational equilibrium, Στ = 0 and ΣF = 0. Lever problems are common on the MCAT; especially relevant to musculoskeletal biomechanics (forearm as a class 3 lever)." },
  // --- Psychology & Sociology ---
  { id: 'dc-mcat-0079', deck_id: 'deck-mcat', sort_order: 79, front: "Piaget's Stages of Cognitive Development", back: "Sensorimotor (0–2 yrs): object permanence. Preoperational (2–7 yrs): symbolic thought, egocentrism, lack of conservation. Concrete operational (7–11 yrs): logical operations on concrete objects. Formal operational (12+ yrs): abstract reasoning." },
  { id: 'dc-mcat-0080', deck_id: 'deck-mcat', sort_order: 80, front: "Vygotsky's Zone of Proximal Development", back: "The range of tasks a learner can accomplish with guidance but not alone. The 'scaffolding' provided by a more knowledgeable person helps a child move through the ZPD. Emphasizes social and cultural context in learning." },
  { id: 'dc-mcat-0081', deck_id: 'deck-mcat', sort_order: 81, front: "Freud's Psychosexual Stages", back: "Oral (0–1), Anal (1–3), Phallic (3–6; Oedipus/Electra complex), Latency (6–puberty), Genital (puberty+). Fixation at a stage (due to frustration or overindulgence) leads to adult personality characteristics associated with that stage." },
  { id: 'dc-mcat-0082', deck_id: 'deck-mcat', sort_order: 82, front: "Freud's Structural Model", back: "Id: unconscious, pleasure principle, instinctual drives. Ego: reality principle, mediates between id and superego. Superego: internalized moral standards ('conscience'). Defense mechanisms protect the ego from anxiety." },
  { id: 'dc-mcat-0083', deck_id: 'deck-mcat', sort_order: 83, front: "Defense Mechanisms", back: "Repression (blocking thoughts from consciousness), denial, projection (attributing own feelings to others), rationalization, displacement (redirecting emotions to a safer target), sublimation (channeling drives constructively), regression." },
  { id: 'dc-mcat-0084', deck_id: 'deck-mcat', sort_order: 84, front: "Classical Conditioning (Pavlov)", back: "Neutral stimulus (NS) repeatedly paired with unconditioned stimulus (UCS) → NS becomes conditioned stimulus (CS) that elicits conditioned response (CR). Principles: acquisition, extinction, spontaneous recovery, generalization, discrimination." },
  { id: 'dc-mcat-0085', deck_id: 'deck-mcat', sort_order: 85, front: "Operant Conditioning (Skinner)", back: "Behavior is shaped by its consequences. Positive reinforcement: add pleasant stimulus → increase behavior. Negative reinforcement: remove unpleasant stimulus → increase behavior. Punishment (positive or negative) → decrease behavior." },
  { id: 'dc-mcat-0086', deck_id: 'deck-mcat', sort_order: 86, front: "Schedules of Reinforcement", back: "Fixed ratio (FR): reinforce after set number of responses (high rate, post-reinforcement pause). Variable ratio (VR): most resistant to extinction (e.g., gambling). Fixed interval (FI): scalloped pattern. Variable interval (VI): steady rate." },
  { id: 'dc-mcat-0087', deck_id: 'deck-mcat', sort_order: 87, front: "Observational Learning (Bandura)", back: "Learning by observing others (models). Requires: attention, retention, reproduction, and motivation. The Bobo doll experiment demonstrated that children imitate aggressive behavior observed in adults. Basis of social learning theory." },
  { id: 'dc-mcat-0088', deck_id: 'deck-mcat', sort_order: 88, front: "Maslow's Hierarchy of Needs", back: "A motivational pyramid: Physiological (food, water, sleep) → Safety → Love/Belonging → Esteem → Self-Actualization. Lower needs must generally be satisfied before higher ones become motivating. Criticized for cultural bias." },
  { id: 'dc-mcat-0089', deck_id: 'deck-mcat', sort_order: 89, front: "Erikson's Stages of Psychosocial Development", back: "Eight stages, each with a conflict: Trust vs. Mistrust (infancy), Autonomy vs. Shame (toddler), Initiative vs. Guilt (preschool), Industry vs. Inferiority (school age), Identity vs. Role Confusion (adolescence), Intimacy vs. Isolation (young adult), Generativity vs. Stagnation (middle adult), Integrity vs. Despair (old age)." },
  { id: 'dc-mcat-0090', deck_id: 'deck-mcat', sort_order: 90, front: "Attribution Theory", back: "Explains how people attribute causes to events. Internal (dispositional) attribution: behavior is due to the person's character. External (situational) attribution: behavior is due to circumstances. Fundamental attribution error: overemphasizing dispositional causes for others' behavior." },
  { id: 'dc-mcat-0091', deck_id: 'deck-mcat', sort_order: 91, front: "Social Stratification", back: "The hierarchical arrangement of individuals in society based on socioeconomic status, power, and prestige. Systems: caste (ascribed, rigid), class (achieved, fluid), meritocracy (based on merit). Socioeconomic status (SES) impacts health outcomes." },
  { id: 'dc-mcat-0092', deck_id: 'deck-mcat', sort_order: 92, front: "Health Disparities", back: "Differences in health outcomes across racial, ethnic, socioeconomic, or geographic groups, often due to systemic inequalities. Social determinants of health (income, education, housing, access to care) are the primary drivers." },
  { id: 'dc-mcat-0093', deck_id: 'deck-mcat', sort_order: 93, front: "Implicit vs. Explicit Bias", back: "Explicit bias: conscious, deliberate attitudes or stereotypes. Implicit bias: unconscious associations that affect behavior without awareness. Both can impact healthcare delivery and contribute to health disparities. Measured by the Implicit Association Test (IAT)." },
  { id: 'dc-mcat-0094', deck_id: 'deck-mcat', sort_order: 94, front: "Socialization", back: "The lifelong process by which individuals learn and internalize the norms, values, and behaviors of their culture. Primary socialization: family and early childhood. Secondary socialization: schools, peers, media." },
  { id: 'dc-mcat-0095', deck_id: 'deck-mcat', sort_order: 95, front: "Social Influence: Conformity, Compliance, Obedience", back: "Conformity: changing behavior to match group norms (Asch's line study). Compliance: agreeing to a direct request. Obedience: following authority figures' directives (Milgram's shock experiment). Social loafing: reduced effort in a group." },
  { id: 'dc-mcat-0096', deck_id: 'deck-mcat', sort_order: 96, front: "Prejudice, Stereotyping, and Discrimination", back: "Stereotype: a fixed, generalized belief about a group. Prejudice: a negative attitude toward a group (affective component). Discrimination: unfair treatment based on group membership (behavioral component). Self-fulfilling prophecy and stereotype threat are related phenomena." },
  { id: 'dc-mcat-0097', deck_id: 'deck-mcat', sort_order: 97, front: "Memory: Encoding, Storage, Retrieval", back: "Encoding: converting information into a neural code. Storage: maintaining information over time (sensory → short-term/working → long-term). Retrieval: accessing stored information. Failure can occur at any stage." },
  { id: 'dc-mcat-0098', deck_id: 'deck-mcat', sort_order: 98, front: "Long-Term Memory Types", back: "Explicit (declarative) memory: episodic (personal events; hippocampus) and semantic (facts; hippocampus). Implicit (non-declarative) memory: procedural (skills; basal ganglia, cerebellum), priming, conditioned responses (amygdala for fear)." },
  { id: 'dc-mcat-0099', deck_id: 'deck-mcat', sort_order: 99, front: "Stress and the HPA Axis", back: "Perceived stress → hypothalamus releases CRH → anterior pituitary releases ACTH → adrenal cortex releases cortisol. Cortisol mobilizes energy (raises blood glucose), suppresses immune system, and inhibits reproduction. Chronic stress = elevated cortisol → harmful effects." },
  { id: 'dc-mcat-0100', deck_id: 'deck-mcat', sort_order: 100, front: "Biological Basis of Behavior: Neurotransmitters", back: "Dopamine: reward, motivation, motor control (Parkinson's). Serotonin: mood, sleep, appetite (↓ in depression). GABA: inhibitory (benzodiazepines enhance GABA). Glutamate: main excitatory NT. Acetylcholine: muscle contraction, memory, REM sleep." },
  { id: 'dc-mcat-0101', deck_id: 'deck-mcat', sort_order: 101, front: "Sleep Stages and Brain Waves", back: "NREM 1: theta waves (light sleep). NREM 2: sleep spindles, K-complexes. NREM 3: delta waves (slow-wave, deep, restorative sleep). REM: theta/beta waves; dreaming; muscle atonia; memory consolidation. REM sleep disorder: lack of muscle atonia." },
  { id: 'dc-mcat-0102', deck_id: 'deck-mcat', sort_order: 102, front: "Sensory Perception: Signal Detection Theory", back: "Hits (correctly detect signal), misses (fail to detect), false alarms (detect absent signal), correct rejections. Sensitivity (d') reflects ability to discriminate signal from noise; criterion (β) reflects decision bias. Important in medical testing." },
  { id: 'dc-mcat-0103', deck_id: 'deck-mcat', sort_order: 103, front: "Gestalt Principles of Perception", back: "Proximity, similarity, continuity, closure, figure-ground, common fate. The brain organizes sensory input into meaningful wholes (Gestalt = 'whole form'). These principles explain how we perceive organized patterns in everyday vision." },
  { id: 'dc-mcat-0104', deck_id: 'deck-mcat', sort_order: 104, front: "Emotion Theories", back: "James-Lange: physiological response first → emotion follows. Cannon-Bard: physiological response and emotion occur simultaneously. Schachter-Singer (Two-Factor): arousal + cognitive label → emotion. Lazarus: cognitive appraisal is necessary for emotion." },
  { id: 'dc-mcat-0105', deck_id: 'deck-mcat', sort_order: 105, front: "Identity and Self-Concept", back: "Self-concept: beliefs and knowledge about oneself. Self-esteem: evaluative component (how good/bad one feels about oneself). Social identity theory (Tajfel): people derive identity from group membership; ingroup favoritism, outgroup derogation." },
  // --- Additional MCAT High-Yield Topics ---
  { id: 'dc-mcat-0106', deck_id: 'deck-mcat', sort_order: 106, front: "Endocrine System: Pituitary Hormones", back: "Anterior pituitary (adenohypophysis): GH, TSH, ACTH, FSH, LH, prolactin (regulated by hypothalamic releasing/inhibiting hormones). Posterior pituitary (neurohypophysis): stores and releases ADH (vasopressin) and oxytocin (made in hypothalamus)." },
  { id: 'dc-mcat-0107', deck_id: 'deck-mcat', sort_order: 107, front: "Renal Tubule: Reabsorption and Secretion", back: "Proximal convoluted tubule: reabsorbs ~67% Na⁺, glucose, amino acids, HCO₃⁻. Loop of Henle: concentrating gradient. DCT: aldosterone regulates Na⁺/K⁺. Collecting duct: ADH regulates water reabsorption. 'Loops' create hyperosmotic medullary gradient." },
  { id: 'dc-mcat-0108', deck_id: 'deck-mcat', sort_order: 108, front: "Renin-Angiotensin-Aldosterone System (RAAS)", back: "Low BP/blood volume → kidney releases renin → cleaves angiotensinogen to angiotensin I → ACE converts to angiotensin II → causes vasoconstriction + aldosterone release (Na⁺/water retention) + ADH release → raises BP." },
  { id: 'dc-mcat-0109', deck_id: 'deck-mcat', sort_order: 109, front: "Cardiac Output", back: "CO = Heart Rate × Stroke Volume. Normal CO ≈ 5 L/min. Stroke volume is influenced by preload (Frank-Starling: more stretch → more force), afterload (resistance against which heart pumps), and contractility." },
  { id: 'dc-mcat-0110', deck_id: 'deck-mcat', sort_order: 110, front: "Hemoglobin Oxygen Dissociation Curve", back: "Sigmoidal curve due to cooperative binding. Shifts right (reduced O₂ affinity) with ↑T, ↑CO₂, ↑[H⁺] (acidosis), ↑2,3-BPG (Bohr effect) — facilitates O₂ unloading in active tissues. Shifts left in lungs (high O₂, low CO₂)." },
  { id: 'dc-mcat-0111', deck_id: 'deck-mcat', sort_order: 111, front: "Blood Pressure Regulation Summary", back: "Short-term: baroreceptors (carotid sinus/aortic arch) → ANS adjustments (HR, vasomotor tone). Long-term: RAAS (sodium/water balance), ADH (water reabsorption). ANS: sympathetic increases BP; parasympathetic decreases HR." },
  { id: 'dc-mcat-0112', deck_id: 'deck-mcat', sort_order: 112, front: "Coagulation Cascade Overview", back: "Extrinsic pathway: tissue factor (III) + VII → activated. Intrinsic pathway: XII, XI, IX, VIII. Both converge at factor X → Xa + Va → prothrombin (II) → thrombin → fibrinogen → fibrin clot. Warfarin blocks vitamin K-dependent factors (II, VII, IX, X)." },
  { id: 'dc-mcat-0113', deck_id: 'deck-mcat', sort_order: 113, front: "Respiratory Control", back: "Chemoreceptors detect changes in blood CO₂, O₂, and pH. Central chemoreceptors (medulla): most sensitive to PCO₂ (via CSF pH). Peripheral chemoreceptors (carotid and aortic bodies): respond to PO₂, PCO₂, and pH. Hypercapnia is the primary respiratory drive." },
  { id: 'dc-mcat-0114', deck_id: 'deck-mcat', sort_order: 114, front: "Muscle Contraction: Cardiac vs. Skeletal", back: "Skeletal: voluntary, multinucleated, no gap junctions, needs all-or-nothing AP per fiber. Cardiac: involuntary, uninucleated, gap junctions (electrical syncytium), longer AP (plateau phase due to Ca²⁺ L-channels), no tetanus." },
  { id: 'dc-mcat-0115', deck_id: 'deck-mcat', sort_order: 115, front: "Immune Response: B vs. T Cells", back: "B cells: mature in bone marrow, produce antibodies (humoral immunity), activated by Th2 cells. T cells: mature in thymus, cell-mediated immunity. CD4+ (helper): activate B cells and cytotoxic T cells. CD8+ (cytotoxic): kill infected/tumor cells." },
  { id: 'dc-mcat-0116', deck_id: 'deck-mcat', sort_order: 116, front: "MHC Class I vs. Class II", back: "MHC I: on all nucleated cells; presents endogenous peptides (intracellular pathogens, cancer) to CD8+ cytotoxic T cells. MHC II: on antigen-presenting cells (macrophages, B cells, dendritic cells); presents exogenous peptides to CD4+ helper T cells." },
  { id: 'dc-mcat-0117', deck_id: 'deck-mcat', sort_order: 117, front: "Complement System", back: "A cascade of plasma proteins that enhances immune response. Three pathways (classical, lectin, alternative) converge at C3 → C3b (opsonization), MAC (lysis), C3a/C5a (anaphylatoxins causing inflammation and chemotaxis)." },
  { id: 'dc-mcat-0118', deck_id: 'deck-mcat', sort_order: 118, front: "Hardy-Weinberg Equilibrium (MCAT)", back: "p² + 2pq + q² = 1; p + q = 1. In a non-evolving population, allele and genotype frequencies remain constant. HWE violations indicate evolutionary forces: selection, mutation, migration, non-random mating, genetic drift." },
  { id: 'dc-mcat-0119', deck_id: 'deck-mcat', sort_order: 119, front: "MCAT: Common Lab Techniques", back: "PCR (amplify DNA), gel electrophoresis (separate by size), Southern blot (detect DNA), Northern blot (detect RNA), Western blot (detect protein), ELISA (quantify protein), flow cytometry (cell sorting), CRISPR (gene editing)." },
  { id: 'dc-mcat-0120', deck_id: 'deck-mcat', sort_order: 120, front: "Statistics: Mean, Median, Mode", back: "Mean: arithmetic average; sensitive to outliers. Median: middle value; robust to outliers; used for skewed distributions (e.g., income). Mode: most frequent value. In a normal distribution, mean = median = mode." },
  { id: 'dc-mcat-0121', deck_id: 'deck-mcat', sort_order: 121, front: "Standard Deviation and Normal Distribution", back: "SD measures spread of data around the mean. In a normal distribution: ±1 SD contains 68%, ±2 SD contains 95%, ±3 SD contains 99.7% of data. Standard error (SE) = SD/√n; measures precision of the mean estimate." },
  { id: 'dc-mcat-0122', deck_id: 'deck-mcat', sort_order: 122, front: "Study Design: Observational vs. Experimental", back: "Observational: cohort (follow exposed/unexposed forward), case-control (compare cases/controls backward), cross-sectional (snapshot in time). Experimental: randomized controlled trial (RCT; gold standard for causality). Blinding reduces bias." },
  { id: 'dc-mcat-0123', deck_id: 'deck-mcat', sort_order: 123, front: "Relative Risk vs. Odds Ratio", back: "Relative risk (RR): used in cohort studies; incidence in exposed / incidence in unexposed. Odds ratio (OR): used in case-control studies; odds of exposure in cases / odds of exposure in controls. OR ≈ RR when disease is rare." },
  { id: 'dc-mcat-0124', deck_id: 'deck-mcat', sort_order: 124, front: "Bias and Confounding", back: "Selection bias: non-representative sampling. Recall bias: differential recall between groups (common in case-control). Confounding: a third variable associated with both exposure and outcome. Controlled by randomization (RCTs) or statistical adjustment." },
  { id: 'dc-mcat-0125', deck_id: 'deck-mcat', sort_order: 125, front: "Urea Cycle", back: "Converts toxic ammonia to urea in the liver (some steps in mitochondria, some in cytoplasm). Net reaction: 2 NH₃ + CO₂ → urea + H₂O. Consumes 3 ATP per cycle. Urea is excreted by the kidneys." },
  { id: 'dc-mcat-0126', deck_id: 'deck-mcat', sort_order: 126, front: "Cholesterol Metabolism", back: "Synthesized in the liver from acetyl-CoA via HMG-CoA reductase (rate-limiting step; inhibited by statins). Transported in LDL (delivers to tissues), HDL (reverse transport to liver). Precursor to steroid hormones, bile acids, vitamin D." },
  { id: 'dc-mcat-0127', deck_id: 'deck-mcat', sort_order: 127, front: "Vitamins: Fat-Soluble (ADEK)", back: "A (retinol): vision, immune function. D (calciferol): Ca²⁺ absorption. E (tocopherol): antioxidant. K (phylloquinone): clotting factors (II, VII, IX, X). Stored in fat; excess is toxic. Deficiency: A→night blindness; D→rickets; K→bleeding." },
  { id: 'dc-mcat-0128', deck_id: 'deck-mcat', sort_order: 128, front: "Vitamins: Water-Soluble", back: "B vitamins (thiamine B1, riboflavin B2, niacin B3, B6, folate B9, B12) and Vitamin C. Not stored (excreted in urine). B12 deficiency: megaloblastic anemia + neurological symptoms; requires intrinsic factor for absorption. Folate deficiency: megaloblastic anemia, neural tube defects." },
  { id: 'dc-mcat-0129', deck_id: 'deck-mcat', sort_order: 129, front: "Cytochrome P450 (CYP) System", back: "A family of liver enzymes responsible for Phase I drug metabolism (oxidation, reduction, hydrolysis). Can be induced (↑ enzyme activity, ↓ drug effect) or inhibited (↓ enzyme activity, ↑ drug levels and toxicity). Example: rifampin induces, grapefruit inhibits." },
  { id: 'dc-mcat-0130', deck_id: 'deck-mcat', sort_order: 130, front: "Receptor Pharmacology: Agonists and Antagonists", back: "Full agonist: activates receptor to maximum response (Emax). Partial agonist: can act as agonist or antagonist depending on context; submaximal Emax. Competitive antagonist: reversible, overcomed by ↑ agonist. Irreversible antagonist: permanently blocks receptor." },
  { id: 'dc-mcat-0131', deck_id: 'deck-mcat', sort_order: 131, front: "Photosynthesis: Light Reactions", back: "In thylakoid membrane: light absorbed by chlorophyll → excites electrons → water is split (O₂ released) → electrons pass through ETC (PSII → PQ → Cyt b6f → PC → PSI → Fd → NADP⁺ reductase → NADPH). ATP produced by photophosphorylation." },
  { id: 'dc-mcat-0132', deck_id: 'deck-mcat', sort_order: 132, front: "Calvin Cycle (MCAT)", back: "3 turns fix 3 CO₂ using 9 ATP and 6 NADPH to produce 1 G3P (net). Three phases: carbon fixation (CO₂ + RuBP → 3-PGA, by RuBisCo), reduction (3-PGA → G3P), regeneration of RuBP. Occurs in stroma." },
  { id: 'dc-mcat-0133', deck_id: 'deck-mcat', sort_order: 133, front: "Lactate Dehydrogenase (LDH)", back: "Enzyme that interconverts pyruvate and lactate using NAD⁺/NADH. During anaerobic glycolysis, LDH regenerates NAD⁺ (converting pyruvate → lactate) allowing glycolysis to continue. Serum LDH is a marker of tissue damage." },
  { id: 'dc-mcat-0134', deck_id: 'deck-mcat', sort_order: 134, front: "Anaplerotic Reactions", back: "Reactions that replenish TCA cycle intermediates that have been used for biosynthesis. The most important: pyruvate + CO₂ → oxaloacetate (by pyruvate carboxylase, activated by acetyl-CoA). Ensures TCA cycle can continue operating." },
  { id: 'dc-mcat-0135', deck_id: 'deck-mcat', sort_order: 135, front: "Purine vs. Pyrimidine Synthesis", back: "Purines (A, G): synthesized de novo on a ribose-5-phosphate scaffold using amino acids, folate, CO₂. Pyrimidines (C, T/U): ring synthesized first, then attached to ribose. Inhibited by methotrexate (folate analog) — used in cancer and autoimmune disease." },
  { id: 'dc-mcat-0136', deck_id: 'deck-mcat', sort_order: 136, front: "Sickle Cell Disease", back: "Autosomal recessive; single point mutation (Glu → Val at position 6 of β-globin). Causes HbS to polymerize under low O₂, deforming RBCs into sickle shape. Heterozygotes (HbAS) have sickle cell trait and some malaria resistance." },
  { id: 'dc-mcat-0137', deck_id: 'deck-mcat', sort_order: 137, front: "Autosomal Dominant vs. Recessive Inheritance", back: "Autosomal dominant: one mutant allele sufficient; affects each generation, M=F. Examples: Huntington's, Marfan syndrome, familial hypercholesterolemia. Autosomal recessive: two mutant alleles required; carriers unaffected; may skip generations. Examples: cystic fibrosis, PKU, sickle cell." },
  { id: 'dc-mcat-0138', deck_id: 'deck-mcat', sort_order: 138, front: "Eukaryotic vs. Prokaryotic Ribosomes", back: "Prokaryotic: 70S (50S + 30S subunits). Eukaryotic: 80S (60S + 40S subunits). Mitochondria and chloroplasts have 70S ribosomes (endosymbiosis). Antibiotics exploit differences: aminoglycosides and tetracyclines target 30S; chloramphenicol and macrolides target 50S." },
  { id: 'dc-mcat-0139', deck_id: 'deck-mcat', sort_order: 139, front: "Osmolality and Tonicity", back: "Osmolality: total concentration of all solutes (mOsm/kg). Tonicity: concentration of solutes that cannot cross the cell membrane (determines cell volume). Hypertonic solution → cell shrinks. Hypotonic → cell swells. Normal plasma osmolality ≈ 285–295 mOsm/kg." },
  { id: 'dc-mcat-0140', deck_id: 'deck-mcat', sort_order: 140, front: "Diabetes Insipidus vs. SIADH", back: "Diabetes insipidus: insufficient ADH (central DI) or unresponsive kidneys (nephrogenic DI) → dilute urine, hypernatremia, polydipsia. SIADH (syndrome of inappropriate ADH): excess ADH → concentrated urine, hyponatremia, water retention." },
  { id: 'dc-mcat-0141', deck_id: 'deck-mcat', sort_order: 141, front: "Lung Volumes and Capacities", back: "Tidal volume (TV): normal breath ~500 mL. IRV: maximum inspiration above TV. ERV: maximum expiration below TV. Residual volume (RV): cannot be exhaled (~1.2 L). FRC = ERV + RV. TLC = TV + IRV + ERV + RV. FEV1/FVC distinguishes obstructive (<70%) from restrictive (normal ratio, reduced TLC)." },
  { id: 'dc-mcat-0142', deck_id: 'deck-mcat', sort_order: 142, front: "Neurotransmitter Metabolism: Monoamines", back: "MAO (monoamine oxidase) degrades dopamine, serotonin, and norepinephrine. MAO inhibitors (MAOIs) treat depression (dangerous tyramine interactions). COMT degrades catecholamines. Reuptake transporters (SERT, DAT, NET) are targets of SSRIs, SNRIs, TCAs, and cocaine." },
  { id: 'dc-mcat-0143', deck_id: 'deck-mcat', sort_order: 143, front: "Pain Pathways", back: "Nociceptors in periphery → afferent fibers (Aδ: fast sharp pain; C fibers: slow burning pain) → dorsal horn → cross midline → spinothalamic tract → thalamus → cortex. Gate control theory: stimulating large Aβ fibers inhibits pain perception." },
  { id: 'dc-mcat-0144', deck_id: 'deck-mcat', sort_order: 144, front: "Hormones: Insulin and Glucagon Actions", back: "Insulin (fed state, β-cells): promotes glucose uptake (GLUT4 in muscle/fat), glycogenesis, lipogenesis, protein synthesis. Inhibits gluconeogenesis and lipolysis. Glucagon (fasted state, α-cells): promotes glycogenolysis, gluconeogenesis, lipolysis, ketogenesis." },
  { id: 'dc-mcat-0145', deck_id: 'deck-mcat', sort_order: 145, front: "Adrenal Cortex Hormones", back: "Zona glomerulosa → mineralocorticoids (aldosterone): Na⁺/K⁺ regulation. Zona fasciculata → glucocorticoids (cortisol): stress response, anti-inflammatory. Zona reticularis → androgens (DHEA). 'GFR' = zona order from outside in." },
  { id: 'dc-mcat-0146', deck_id: 'deck-mcat', sort_order: 146, front: "Thyroid Hormone Synthesis", back: "Iodide trapping → oxidation to I₂ → iodination of tyrosines on thyroglobulin (MIT, DIT) → coupling (T3, T4) → storage in follicle → proteolysis → secretion. T4 is converted to active T3 by deiodinases in periphery. TSH stimulates all steps." },
  { id: 'dc-mcat-0147', deck_id: 'deck-mcat', sort_order: 147, front: "Calcium Regulation", back: "PTH (parathyroid hormone): ↑ Ca²⁺ by ↑ bone resorption, ↑ renal reabsorption, ↑ calcitriol synthesis (→ intestinal absorption). Calcitonin (thyroid C cells): ↓ Ca²⁺ (minor role in humans). Vitamin D (calcitriol): ↑ intestinal Ca²⁺ and PO₄³⁻ absorption." },
  { id: 'dc-mcat-0148', deck_id: 'deck-mcat', sort_order: 148, front: "Fertilization to Implantation", back: "Fertilization: sperm + secondary oocyte in fallopian tube → zygote. Cleavage → morula → blastocyst. Blastocyst implants into endometrium (~day 6). Trophoblast invades uterine wall; inner cell mass forms embryo. hCG maintains corpus luteum." },
  { id: 'dc-mcat-0149', deck_id: 'deck-mcat', sort_order: 149, front: "Germ Layers and Derivatives", back: "Ectoderm: skin epidermis, nervous system (neural tube → CNS; neural crest → PNS, adrenal medulla, melanocytes). Mesoderm: muscle, bone, connective tissue, cardiovascular, urogenital. Endoderm: epithelial linings of GI, respiratory, bladder." },
  { id: 'dc-mcat-0150', deck_id: 'deck-mcat', sort_order: 150, front: "Apoptosis vs. Necrosis", back: "Apoptosis: programmed, energy-dependent; orderly packaging of cell contents (apoptotic bodies phagocytosed; no inflammation). Caspase cascade. Necrosis: uncontrolled death from injury; cell swelling, membrane rupture, spillage of contents → inflammation." },
  { id: 'dc-mcat-0151', deck_id: 'deck-mcat', sort_order: 151, front: "p53 Tumor Suppressor", back: "The 'guardian of the genome.' Activated by DNA damage → triggers p21 (CDK inhibitor, halts cell cycle at G1/S) or apoptosis. Mutated in >50% of all human cancers. Both alleles must be lost (two-hit hypothesis)." },
  { id: 'dc-mcat-0152', deck_id: 'deck-mcat', sort_order: 152, front: "Oncogene RAS", back: "A proto-oncogene encoding a GTPase in the MAPK signaling pathway. Mutant RAS is constitutively active (GTP-bound, cannot hydrolyze GTP → permanently signals cell growth). Mutated in ~30% of human cancers. A gain-of-function dominant mutation." },
  { id: 'dc-mcat-0153', deck_id: 'deck-mcat', sort_order: 153, front: "Ion Channels and Patch Clamp", back: "Ion channels are membrane proteins that open/close in response to voltage, ligands, or mechanical stimuli. Patch-clamp technique: attaches a glass pipette to a tiny membrane patch to measure current through individual channels. Used to characterize channel behavior." },
  { id: 'dc-mcat-0154', deck_id: 'deck-mcat', sort_order: 154, front: "Acetylcholine: Nicotinic vs. Muscarinic Receptors", back: "Nicotinic receptors: ligand-gated ion channels (Na⁺/K⁺); at NMJ and autonomic ganglia; blocked by curare (NMJ) or hexamethonium (ganglia). Muscarinic receptors: GPCRs; at target organs of parasympathetic nervous system; blocked by atropine." },
  { id: 'dc-mcat-0155', deck_id: 'deck-mcat', sort_order: 155, front: "Autonomic Nervous System", back: "Sympathetic ('fight or flight'): thoracolumbar origin; short pre-, long post-ganglionic; NE at target organs (except sweat glands/ACh). Parasympathetic ('rest and digest'): craniosacral; long pre-, short post-ganglionic; ACh at all junctions." },
  { id: 'dc-mcat-0156', deck_id: 'deck-mcat', sort_order: 156, front: "Blood Types and Rh Factor", back: "ABO system: A (A antigens, anti-B), B (B antigens, anti-A), AB (both antigens, no antibodies; universal recipient), O (no antigens, anti-A and anti-B; universal donor). Rh+ has D antigen; Rh- lacks it. Rh incompatibility can cause hemolytic disease of the newborn." },
  { id: 'dc-mcat-0157', deck_id: 'deck-mcat', sort_order: 157, front: "Protein Folding and Chaperones", back: "Protein folding is spontaneous, driven by hydrophobic collapse and entropy of water. Molecular chaperones (Hsp70, Hsp90, GroEL/GroES) prevent misfolding and aggregation, especially under stress. Misfolded proteins → proteasome degradation or aggregation diseases (prions, Alzheimer's)." },
  { id: 'dc-mcat-0158', deck_id: 'deck-mcat', sort_order: 158, front: "Allosteric Regulation vs. Covalent Modification", back: "Allosteric: non-covalent binding of an effector at a site other than the active site changes enzyme conformation and activity (reversible). Covalent modification: phosphorylation/dephosphorylation by kinases/phosphatases alters enzyme activity (reversible but requires ATP)." },
  { id: 'dc-mcat-0159', deck_id: 'deck-mcat', sort_order: 159, front: "Zymogen Activation", back: "Zymogens (enzyme precursors) are secreted in an inactive form and activated by proteolytic cleavage. Prevents damage to secretory organs. Examples: pepsinogen → pepsin (stomach acid); trypsinogen → trypsin (enterokinase in duodenum); prothrombin → thrombin." },
  { id: 'dc-mcat-0160', deck_id: 'deck-mcat', sort_order: 160, front: "Enzyme Cofactors and Coenzymes", back: "Cofactors: inorganic ions (Fe²⁺, Mg²⁺, Zn²⁺) required for enzyme activity. Coenzymes: organic molecules (often vitamins) that carry chemical groups: NAD⁺ (niacin, B3), FAD (riboflavin, B2), Coenzyme A (pantothenate, B5), TPP (thiamine, B1), PLP (B6)." },
  { id: 'dc-mcat-0161', deck_id: 'deck-mcat', sort_order: 161, front: "Fluid Mosaic Model", back: "Proposed by Singer and Nicolson (1972). The cell membrane is a fluid (dynamic, laterally mobile) bilayer of phospholipids with embedded proteins. Cholesterol increases membrane fluidity at low T and decreases it at high T (stabilizes membrane)." },
  { id: 'dc-mcat-0162', deck_id: 'deck-mcat', sort_order: 162, front: "Second Messengers Summary", back: "cAMP (from adenylyl cyclase via Gs): activates PKA. cGMP (from guanylyl cyclase): activates PKG (e.g., NO → vasodilation). IP₃ (from PLC via Gq): releases Ca²⁺ from ER. DAG (from PLC): activates PKC. Ca²⁺: activates calmodulin, various kinases." },
  { id: 'dc-mcat-0163', deck_id: 'deck-mcat', sort_order: 163, front: "Restriction Enzymes and Recombinant DNA", back: "Type II restriction enzymes cut dsDNA at specific palindromic sequences, producing sticky or blunt ends. DNA ligase joins fragments. Recombinant DNA technology uses these tools to clone genes into vectors for expression in host cells (E. coli, yeast)." },
  { id: 'dc-mcat-0164', deck_id: 'deck-mcat', sort_order: 164, front: "Southern, Northern, Western Blot", back: "Southern: DNA separated by gel electrophoresis, transferred to membrane, probed with labeled DNA. Northern: same but for RNA. Western: protein separated by SDS-PAGE, transferred, detected by antibody. 'SNoW DRoP' = South DNA, North RNA, West Protein." },
  { id: 'dc-mcat-0165', deck_id: 'deck-mcat', sort_order: 165, front: "ELISA (Enzyme-Linked Immunosorbent Assay)", back: "Uses antibodies and enzyme-linked detection to quantify an antigen in a sample. Types: direct, indirect, sandwich (most sensitive). The enzyme produces a color change proportional to antigen concentration. Used to detect HIV antibodies, hormones, and drugs." },
  { id: 'dc-mcat-0166', deck_id: 'deck-mcat', sort_order: 166, front: "Carboxylic Acid Derivatives Reactivity", back: "Acyl chloride > Anhydride > Ester > Amide (decreasing reactivity in nucleophilic acyl substitution). Better leaving group = more reactive. Acid chlorides are made from carboxylic acids + thionyl chloride or PCl₅. All can be hydrolyzed to the parent acid." },
  { id: 'dc-mcat-0167', deck_id: 'deck-mcat', sort_order: 167, front: "Oxidation States of Carbon in Organic Compounds", back: "Most reduced: CH₄ (C = -4). Increasingly oxidized: CH₃OH (alcohol, -2) → RCHO (aldehyde, 0) → RCOOH (carboxylic acid, +2) → CO₂ (+4). Moving toward carboxylic acid = oxidation (gain of O or loss of H)." },
  { id: 'dc-mcat-0168', deck_id: 'deck-mcat', sort_order: 168, front: "Spectroscopy: ¹H NMR Interpretation", back: "Chemical shift (δ, ppm): indicates electronic environment. Splitting: n equivalent neighbors → n+1 peaks (n+1 rule). Integration: proportional to number of protons. Downfield (high δ): deshielded (near electronegative atoms or π systems). TMS = reference (0 ppm)." },
  { id: 'dc-mcat-0169', deck_id: 'deck-mcat', sort_order: 169, front: "Keto-Enol Tautomerism", back: "A rapid equilibrium between a keto form (C=O with α-H) and an enol form (C=C with OH). The keto form usually predominates. Tautomerism is catalyzed by acid or base. Enols are important intermediates in many biological reactions." },
  { id: 'dc-mcat-0170', deck_id: 'deck-mcat', sort_order: 170, front: "Claisen Condensation", back: "A condensation between two esters (or an ester and a ketone — Claisen-Schmidt) using a strong base. Forms a β-keto ester. The biological equivalent is thiolase in β-oxidation (two acetyl-CoA units condense to form acetoacetyl-CoA)." },
  { id: 'dc-mcat-0171', deck_id: 'deck-mcat', sort_order: 171, front: "Diels-Alder Reaction", back: "A [4+2] cycloaddition between a diene (in s-cis conformation) and a dienophile (electron-poor alkene). Forms a six-membered ring. Stereospecific: syn addition, endo rule. Important in natural product synthesis." },
  { id: 'dc-mcat-0172', deck_id: 'deck-mcat', sort_order: 172, front: "Free Radical Reactions", back: "Three stages: initiation (homolytic bond cleavage by heat/light → radicals), propagation (radical reacts with substrate, generating new radicals), termination (two radicals combine → no new radicals). Halogenation of alkanes is a free radical reaction." },
  { id: 'dc-mcat-0173', deck_id: 'deck-mcat', sort_order: 173, front: "Polarity and Solubility", back: "Like dissolves like: polar solvents (water) dissolve polar/ionic substances; nonpolar solvents (hexane) dissolve nonpolar substances. Amphipathic molecules (soaps, phospholipids) have both polar and nonpolar regions and act as emulsifiers." },
  { id: 'dc-mcat-0174', deck_id: 'deck-mcat', sort_order: 174, front: "Resonance and Stability", back: "Resonance structures delocalize electrons, stabilizing the molecule. More resonance contributors = greater stability. Carboxylate anion (2 equivalent structures) is more stable than an alkoxide (1 structure). Benzene's 6-π electron delocalization confers aromatic stability." },
  { id: 'dc-mcat-0175', deck_id: 'deck-mcat', sort_order: 175, front: "Magnetism and MRI", back: "MRI uses powerful magnetic fields to align hydrogen nuclei (protons), which are then perturbed by radiofrequency pulses. As they relax back, they emit signals used to construct images. T1 (fat bright) and T2 (fluid bright) are relaxation parameters. No ionizing radiation." },
  { id: 'dc-mcat-0176', deck_id: 'deck-mcat', sort_order: 176, front: "Surface Tension and Lung Compliance", back: "Surface tension of alveolar fluid tends to collapse alveoli. Surfactant (dipalmitoylphosphatidylcholine, produced by type II pneumocytes) reduces surface tension, increasing lung compliance and preventing alveolar collapse. Deficient in premature infants (NRDS)." },
  { id: 'dc-mcat-0177', deck_id: 'deck-mcat', sort_order: 177, front: "Laplace's Law (Pressure-Volume)", back: "P = 2T/r (sphere). The pressure required to keep a sphere inflated is inversely proportional to its radius. Small alveoli (r) would tend to collapse into larger ones unless surfactant reduces T disproportionately in smaller alveoli." },
  { id: 'dc-mcat-0178', deck_id: 'deck-mcat', sort_order: 178, front: "Electrophoresis: SDS-PAGE", back: "Proteins denatured with SDS (gives uniform negative charge proportional to size) then separated by size through polyacrylamide gel in an electric field. Smaller proteins migrate faster. Followed by Western blot or Coomassie staining." },
  { id: 'dc-mcat-0179', deck_id: 'deck-mcat', sort_order: 179, front: "Thin Layer Chromatography (TLC)", back: "Separates compounds by polarity on a silica-coated plate. Mobile phase (solvent) travels up by capillary action. Rf = distance moved by compound / distance moved by solvent front. Polar compounds have low Rf on normal-phase silica." },
  { id: 'dc-mcat-0180', deck_id: 'deck-mcat', sort_order: 180, front: "Isoelectric Focusing", back: "Electrophoretic technique separating proteins by their isoelectric point (pI) in a pH gradient. Proteins migrate until they reach the pH equal to their pI and stop (net charge = 0). Used to identify protein isoforms and in proteomics." },
  { id: 'dc-mcat-0181', deck_id: 'deck-mcat', sort_order: 181, front: "Cystic Fibrosis Pathophysiology", back: "Autosomal recessive mutation in CFTR gene (most common: ΔF508). CFTR is a Cl⁻ channel; dysfunction → thick, sticky mucus in lungs and digestive tract. Features: chronic respiratory infections, pancreatic insufficiency, infertility (males). Sweat chloride test >60 mEq/L is diagnostic." },
  { id: 'dc-mcat-0182', deck_id: 'deck-mcat', sort_order: 182, front: "Huntington's Disease", back: "Autosomal dominant neurodegenerative disease caused by CAG trinucleotide repeat expansion in HTT gene (>36 repeats) → toxic polyglutamine huntingtin protein. Loss of GABAergic neurons in the striatum. Chorea, dementia, psychiatric symptoms. Onset typically 30–50 years." },
  { id: 'dc-mcat-0183', deck_id: 'deck-mcat', sort_order: 183, front: "Phenylketonuria (PKU)", back: "Autosomal recessive deficiency of phenylalanine hydroxylase (PAH) → phenylalanine accumulates → converted to phenylketones (neurotoxic). Presents with intellectual disability, seizures, musty odor. Detected on newborn screening; treated with low-phenylalanine diet." },
  { id: 'dc-mcat-0184', deck_id: 'deck-mcat', sort_order: 184, front: "Lysosomal Storage Diseases", back: "Caused by deficiencies in lysosomal hydrolases → accumulation of substrates. Examples: Gaucher's (glucocerebrosidase; most common), Tay-Sachs (hexosaminidase A; cherry-red spot), Niemann-Pick (sphingomyelinase), Hurler syndrome (α-L-iduronidase)." },
  { id: 'dc-mcat-0185', deck_id: 'deck-mcat', sort_order: 185, front: "Insulin Signaling Pathway", back: "Insulin binds RTK (insulin receptor) → autophosphorylation of tyrosine residues → IRS-1 phosphorylation → PI3K activation → Akt phosphorylation → GLUT4 translocation to membrane (↑ glucose uptake), glycogen synthesis, protein synthesis, and anti-apoptosis." },
  { id: 'dc-mcat-0186', deck_id: 'deck-mcat', sort_order: 186, front: "Notch Signaling", back: "A cell-cell contact signaling pathway. Ligand (Delta/Jagged) on one cell binds Notch receptor on adjacent cell → γ-secretase cleaves Notch intracellular domain (NICD) → NICD enters nucleus → activates target genes. Critical in cell fate determination and development." },
  { id: 'dc-mcat-0187', deck_id: 'deck-mcat', sort_order: 187, front: "Wnt Signaling", back: "Wnt ligand binds Frizzled receptor → inhibits destruction complex → β-catenin accumulates → enters nucleus → activates target genes (cell proliferation, differentiation). Dysregulated Wnt signaling is common in colorectal cancer (APC mutation)." },
  { id: 'dc-mcat-0188', deck_id: 'deck-mcat', sort_order: 188, front: "Oxidative Stress and Antioxidants", back: "Reactive oxygen species (ROS: superoxide O₂⁻, H₂O₂, hydroxyl radical OH•) damage DNA, lipids, and proteins. Antioxidant defenses: superoxide dismutase (SOD), catalase, glutathione peroxidase (requires NADPH from PPP). Vitamin C, E also antioxidants." },
  { id: 'dc-mcat-0189', deck_id: 'deck-mcat', sort_order: 189, front: "Replication Fork and Telomeres", back: "DNA polymerase can only extend 3' ends; new strand synthesized 5'→3'. Lagging strand requires Okazaki fragments. Each replication shortens chromosomes at ends (end replication problem). Telomerase (reverse transcriptase) adds TTAGGG repeats; active in germ cells and cancer cells." },
  { id: 'dc-mcat-0190', deck_id: 'deck-mcat', sort_order: 190, front: "X-Inactivation (Lyon Hypothesis)", back: "In female mammals, one X chromosome is randomly inactivated in each somatic cell early in development (forming a Barr body). The inactivated X is transcriptionally silenced by XIST RNA and DNA methylation. Inactivation is clonal; females are mosaics for X-linked traits." },
  { id: 'dc-mcat-0191', deck_id: 'deck-mcat', sort_order: 191, front: "Genomic Imprinting", back: "Some genes are expressed only from the maternally or paternally inherited allele, regulated by DNA methylation patterns set in gametes. Prader-Willi (paternal 15q11 deletion → no paternal copy) and Angelman syndrome (maternal 15q11 deletion → no maternal UBE3A)." },
  { id: 'dc-mcat-0192', deck_id: 'deck-mcat', sort_order: 192, front: "Gene Therapy Approaches", back: "Viral vectors (lentivirus, AAV, retrovirus) deliver functional gene copies into patient cells. Ex vivo: cells removed, modified, reinfused (e.g., CAR-T cells). In vivo: vector delivered directly. CRISPR enables precise genome editing. Used for hemophilia, LCA, certain immunodeficiencies." },
  { id: 'dc-mcat-0193', deck_id: 'deck-mcat', sort_order: 193, front: "Pharmacokinetics: ADME", back: "Absorption (route of administration, bioavailability, first-pass effect), Distribution (Vd, plasma protein binding), Metabolism (Phase I: CYP450 oxidation; Phase II: conjugation → more water-soluble), Excretion (renal, biliary). These four processes determine drug concentration over time." },
  { id: 'dc-mcat-0194', deck_id: 'deck-mcat', sort_order: 194, front: "Proton NMR: Number of Signals", back: "Each chemically non-equivalent proton in a molecule gives a distinct NMR signal. Equivalent protons (related by symmetry) give one signal. The number of signals indicates the number of chemically unique proton environments in the molecule." },
  { id: 'dc-mcat-0195', deck_id: 'deck-mcat', sort_order: 195, front: "Mass Spectrometry", back: "Molecules are ionized and fragmented; detected by mass-to-charge ratio (m/z). The molecular ion peak (M⁺) gives molecular weight. Fragmentation patterns reveal structure. Base peak: most abundant fragment. Used to identify unknowns in organic chemistry." },
  { id: 'dc-mcat-0196', deck_id: 'deck-mcat', sort_order: 196, front: "Acid-Base Properties of Amino Acids", back: "Each amino acid has at least two pKa values: α-NH₃⁺ (pKa ~9) and α-COOH (pKa ~2). Side chain pKa values vary. Below pKa of COOH: fully protonated (+1 charge). Above pKa of NH₃⁺: fully deprotonated (−1 charge). pI = average of relevant pKa values." },
  { id: 'dc-mcat-0197', deck_id: 'deck-mcat', sort_order: 197, front: "Kidney Tubular Secretion and Drug Elimination", back: "Organic anion transporters (OATs) and cation transporters actively secrete drugs into tubular fluid for excretion. Probenecid blocks OATs (reduces penicillin/uric acid secretion). Drug ionization affects reabsorption: ionized forms are trapped in urine (ion trapping)." },
  { id: 'dc-mcat-0198', deck_id: 'deck-mcat', sort_order: 198, front: "Poverty and Health Outcomes", back: "Low SES is associated with higher rates of cardiovascular disease, diabetes, infections, mental illness, and infant mortality. Mechanisms: limited access to healthcare, poor nutrition, chronic stress (allostatic load), environmental exposures, and reduced health literacy." },
  { id: 'dc-mcat-0199', deck_id: 'deck-mcat', sort_order: 199, front: "Cultural Competence in Medicine", back: "The ability of healthcare providers to understand, communicate with, and effectively interact with patients from diverse cultural backgrounds. Reduces healthcare disparities. Involves awareness of implicit biases and culturally specific health beliefs." },
  { id: 'dc-mcat-0200', deck_id: 'deck-mcat', sort_order: 200, front: "Stereotype Threat", back: "A situational predicament in which members of a stigmatized group fear confirming a negative stereotype about their group, leading to impaired performance. Steele and Aronson (1995) demonstrated its effect on African-American students' test performance. Highly relevant for health disparities." },
];
